package NewProject.example.hospital.management.system.Controls;import NewProject.example.hospital.management.system.DTO.Patient.PatientRequestDTO;import NewProject.example.hospital.management.system.DTO.Patient.PatientResponseDTO;import NewProject.example.hospital.management.system.Entity.Patient;import NewProject.example.hospital.management.system.Service.PatientServices;import lombok.AllArgsConstructor;import org.springframework.http.HttpStatus;import org.springframework.http.ResponseEntity;import org.springframework.web.bind.annotation.*;import java.util.List;import java.util.Map;@RestController@RequestMapping("/Patient_Api")@AllArgsConstructorpublic class PatientControls{    private final PatientServices patientServices;    @PostMapping    public ResponseEntity<PatientResponseDTO> createPatient(            @RequestBody PatientRequestDTO patientRequestDTO) {        return ResponseEntity.status(HttpStatus.CREATED)                .body(patientServices.createNewPatient(patientRequestDTO)                );    }    @PostMapping("/MultiplePatient")    public ResponseEntity<List<PatientResponseDTO>> createMultiplePatients(            @RequestBody List<PatientRequestDTO> patientRequestDTOs) {        return ResponseEntity.status(HttpStatus.CREATED)                .body(patientServices.createMultiplePatients(patientRequestDTOs));    }    @GetMapping("/{patientId}")    public ResponseEntity<Patient> getPatientProfile(@PathVariable Long patientId){        Patient patient = patientServices.getPatientById(patientId);        return ResponseEntity.ok(patient);    }    @GetMapping    public ResponseEntity<List<PatientResponseDTO>> getAllPatients(            @RequestParam(defaultValue = "0") Integer pageNumber,            @RequestParam(defaultValue = "10") Integer pageSize){        return ResponseEntity.ok(patientServices.getALLPatient(pageNumber, pageSize));    }    @DeleteMapping("/id/{id}")    public ResponseEntity<String> deletePatient(@PathVariable Long id) {        patientServices.deletePatient(id);        return ResponseEntity.ok(                "Patient deleted successfully with id: " + id        );    }        @DeleteMapping("/name/{firstName}")    public ResponseEntity<String> deletePatientsByName(            @PathVariable String firstName) {        patientServices.deleteByName(firstName);        return ResponseEntity.ok(                " patients with name '" + firstName + "' deleted successfully"        );    }    @PutMapping("/{id}")    public ResponseEntity<PatientResponseDTO> updatePatient(            @PathVariable Long id,            @RequestBody PatientRequestDTO patientRequestDTO) {        PatientResponseDTO updatedPatient = patientServices.updateOldPatient(id, patientRequestDTO);        return ResponseEntity.ok(updatedPatient);    }    @PatchMapping("/{id}")    public ResponseEntity<PatientResponseDTO> updatePatientPartially(            @PathVariable Long id,            @RequestBody Map<String, Object> updates) {        PatientResponseDTO updatedPatient = patientServices.updatePatientPartially(id, updates);        return ResponseEntity.ok(updatedPatient);    }}